class Solution:
    def maxFreqSum(self, s):
        vowels = set('aeiou')
        vmax = 0
        cmax = 0
        for ch in set(s):
            c = s.count(ch)
            if ch in vowels:
                if c > vmax:
                    vmax = c
            else:
                if c > cmax:
                    cmax = c
        return vmax + cmax

