var maxFreqSum = function(s) {
    const vowels = new Set(['a', 'e', 'i', 'o', 'u']);
    const cnt = {};
    for (const ch of s) cnt[ch] = (cnt[ch] || 0) + 1;
    let vmax = 0, cmax = 0;
    for (const ch in cnt) {
        if (vowels.has(ch)) vmax = Math.max(vmax, cnt[ch]);
        else cmax = Math.max(cmax, cnt[ch]);
    }
    return vmax + cmax;
};
